#include <stdio.h>
int max(int a, int b) { return (a > b) ? a : b; }
int knapsack(int n, int W, int wt[], int val[]) {
    int dp[n][W + 1];
    for (int i = 0; i <= n; i++) {
        for (int w = 0; w <= W; w++) {
            if (i == 0 || w == 0)
                dp[i][w] = 0;
            else if (wt[i - 1] <= w)
                dp[i][w] = max(val[i - 1] + dp[i][w - wt[i - 1]], dp[i - 1][w]);
            else
                dp[i][w] = dp[i - 1][w];
        }
    }
    return dp[n][W];
}
int main() {
    int n = 4, W = 10;
    int wt[] = {2, 4, 6, 8};
    int val[] = {5, 11, 13, 17};
    printf("%d\n", knapsack(n, W, wt, val));
    return 0;
}

