class Solution {
    knapsackUtil(wt, val, ind, W, dp) {
        if (ind === 0) {
            return Math.floor(W / wt[0]) * val[0];
        }
        if (dp[ind][W] !== -1) return dp[ind][W];
        let notTaken = this.knapsackUtil(wt, val, ind - 1, W, dp);
        let taken = Number.NEGATIVE_INFINITY;
        if (wt[ind] <= W) {
            taken = val[ind] + this.knapsackUtil(wt, val, ind, W - wt[ind], dp);
        }
        dp[ind][W] = Math.max(notTaken, taken);
        return dp[ind][W];
    }

    unboundedKnapsack(n, W, val, wt) {
        let dp = Array.from({ length: n }, () => Array(W + 1).fill(-1));
        return this.knapsackUtil(wt, val, n - 1, W, dp);
    }
}
